// Hardcode all files - simple and reliable (v2 - Token Optimized)
const baseUrl = 'https://raw.githubusercontent.com/Squidgy-AI/squidgy_updated_ui/main/knowledge_base';

const files = [
  // SHARED (5 files - compressed format files)
  { agent_id: 'shared', source_file: 'security_rules.md', url: `${baseUrl}/shared/security_rules.md` },
  { agent_id: 'shared', source_file: 'button_patterns.md', url: `${baseUrl}/shared/button_patterns.md` },
  { agent_id: 'shared', source_file: 'response_format.md', url: `${baseUrl}/shared/response_format.md` },
  { agent_id: 'shared', source_file: 'content_previews.md', url: `${baseUrl}/shared/content_previews.md` },
  { agent_id: 'shared', source_file: 'actions_format.md', url: `${baseUrl}/shared/actions_format.md` },

  // PERSONAL ASSISTANT (2 files - core + onboarding)
  { agent_id: 'personal_assistant', source_file: 'instructions.md', url: `${baseUrl}/agents/personal_assistant/instructions.md` },
  { agent_id: 'personal_assistant', source_file: 'onboarding_flow.md', url: `${baseUrl}/agents/personal_assistant/onboarding_flow.md` },

  // NEWSLETTER MULTI (2 files)
  { agent_id: 'newsletter_multi', source_file: 'instructions.md', url: `${baseUrl}/agents/newsletter_multi/instructions.md` },
  { agent_id: 'newsletter_multi', source_file: 'custom_instructions.md', url: `${baseUrl}/agents/newsletter_multi/custom_instructions.md` },

  // CONTENT REPURPOSER (2 files)
  { agent_id: 'content_repurposer', source_file: 'instructions.md', url: `${baseUrl}/agents/content_repurposer/instructions.md` },
  { agent_id: 'content_repurposer', source_file: 'custom_instructions.md', url: `${baseUrl}/agents/content_repurposer/custom_instructions.md` },

  // SMM (2 files)
  { agent_id: 'smm', source_file: 'instructions.md', url: `${baseUrl}/agents/smm/instructions.md` },
  { agent_id: 'smm', source_file: 'custom_instructions.md', url: `${baseUrl}/agents/smm/custom_instructions.md` },

  // SOL (3 files - includes domain knowledge)
  { agent_id: 'sol', source_file: 'instructions.md', url: `${baseUrl}/agents/sol/instructions.md` },
  { agent_id: 'sol', source_file: 'custom_instructions.md', url: `${baseUrl}/agents/sol/custom_instructions.md` },
  { agent_id: 'sol', source_file: 'domain_knowledge.md', url: `${baseUrl}/agents/sol/domain_knowledge.md` }
];

// Total: 16 files (added sol/domain_knowledge.md)
return files.map(f => ({ json: f }));

// Process ALL items and merge file info with content
const allFiles = $('Define All Files').all();
const allResponses = $input.all();

const results = [];

for (let i = 0; i < allFiles.length; i++) {
  const fileInfo = allFiles[i].json;
  const rawContent = allResponses[i]?.json || {};

  // Handle response - could be string or object with data property
  let document = '';
  if (typeof rawContent === 'string') {
    document = rawContent;
  } else if (rawContent.data) {
    document = rawContent.data;
  } else if (rawContent.body) {
    document = rawContent.body;
  } else {
    document = JSON.stringify(rawContent);
  }

  results.push({
    json: {
      agent_id: fileInfo.agent_id,
      source_file: fileInfo.source_file,
      document: document
    }
  });
}

return results;

// Merge document info with embeddings
const allDocs = $('Prepare Document').all();
const allEmbeddings = $input.all();

const results = [];

for (let i = 0; i < allDocs.length; i++) {
  const doc = allDocs[i].json;
  const embeddingResponse = allEmbeddings[i]?.json || {};

  // Extract embedding from response
  const embedding = embeddingResponse.data?.[0]?.embedding || [];

  results.push({
    json: {
      agent_id: doc.agent_id,
      source_file: doc.source_file,
      document: doc.document,
      embedding: embedding
    }
  });
}

return results;

const items = $input.all();

return {
  json: {
    success: true,
    total_files: items.length,
    timestamp: new Date().toISOString()
  }
};
